mapper.select:
SELECT t.id, t.name, t.competition_id, c.name AS competition_name, t.leader_id, u.nickname AS leader_name, t.intro, t.total_size, t.current_size, t.college, t.status, t.create_time, ( SELECT GROUP_CONCAT(CONCAT(r.position, '×', (r.count - r.filled)) SEPARATOR ', ') FROM team_recruit r WHERE r.team_id = t.id AND r.count > r.filled ) AS vacancies FROM team t LEFT JOIN competition c ON c.id = t.competition_id LEFT JOIN user u ON u.id = t.leader_id
AND t.competition_id = #{q.competitionId}
AND t.college = #{q.college}
AND u.grade = #{q.grade}
AND t.status = #{q.status}
AND (t.name LIKE CONCAT('%', #{q.keyword}, '%') OR t.intro LIKE CONCAT('%', #{q.keyword}, '%'))
AND EXISTS ( SELECT 1 FROM team_recruit r2 WHERE r2.team_id = t.id AND r2.position LIKE CONCAT('%', #{q.skill}, '%') )
ORDER BY t.create_time DESC
